const files = $('📨 Wiadomość ze Slacka').first().json.files;

return files
  .filter(file => file.mimetype !== 'audio/mp4')
  .map(file => ({ json: file }));

const files = $('📨 Wiadomość ze Slacka').first().json.files || [];
const result = files.length === 0 || (files.length === 1 && files[0].mimetype === 'audio/mp4');
return [{ json: { onlyAudioOrEmpty: result } }];

